bool evaluateBooleanExpression(string expression) {
    stack<char> s;
    for (char c : expression) {
        if (c == ',') continue;
        if (c != ')') {
            s.push(c);
        } else {
            vector<char> seen;
            while (s.top() != '(') {
                seen.push_back(s.top());
                s.pop();
            }
            s.pop(); // remove '('
            char op = s.top();
            s.pop(); // remove operator

            if (op == '!') {
                s.push(seen[0] == 't' ? 'f' : 't');
            } else if (op == '&') {
                bool res = true;
                for (char val : seen) if (val == 'f') res = false;
                s.push(res ? 't' : 'f');
            } else if (op == '|') {
                bool res = false;
                for (char val : seen) if (val == 't') res = true;
                s.push(res ? 't' : 'f');
            }
        }
    }
    return s.top() == 't';
}

code.Python3:
def evaluateBooleanExpression(expression):
    stack = []
    for char in expression:
        if char == ',': continue
        if char != ')':
            stack.append(char)
        else:
            seen = []
            while stack[-1] != '(':
                seen.append(stack.pop())
            stack.pop() # remove (
            op = stack.pop()
            if op == '!':
                stack.append('t' if seen[0] == 'f' else 'f')
            elif op == '&':
                stack.append('f' if 'f' in seen else 't')
            elif op == '|':
                stack.append('t' if 't' in seen else 'f')
    return stack[0] == 't'

code.C:
bool evaluateBooleanExpression(char* booleanExpression) {

    char stack[20005];
    int top = -1;
    for (int i = 0; booleanExpression[i] != '\0'; i++) {
        if (booleanExpression[i] == ',') continue;
        if (booleanExpression[i] != ')') {
            stack[++top] = booleanExpression[i];
        } else {
            bool hasT = false, hasF = false;
            while (stack[top] != '(') {
                if (stack[top] == 't') hasT = true;
                if (stack[top] == 'f') hasF = true;
                top--;
            }
            top--; // remove '('
            char op = stack[top--];
            if (op == '!') stack[++top] = hasT ? 'f' : 't';
            else if (op == '&') stack[++top] = hasF ? 'f' : 't';
            else if (op == '|') stack[++top] = hasT ? 't' : 'f';
        }
    }
    return stack[top] == 't';
}

code.Java:
class Codechef {
    public boolean booleanExpression(String expression) {
        Stack<Character> stack = new Stack<>();

        for (char c : expression.toCharArray()) {
            if (c == ',') continue;

            if (c != ')') {
                stack.push(c);
            } else {
                // Collect elements inside the parentheses
                boolean hasTrue = false;
                boolean hasFalse = false;

                while (stack.peek() != '(') {
                    char top = stack.pop();
                    if (top == 't') hasTrue = true;
                    if (top == 'f') hasFalse = true;
                }

                stack.pop(); // Remove '('
                char op = stack.pop(); // Get operator (!, &, |)

                // Apply logic
                if (op == '!') {
                    stack.push(hasTrue ? 'f' : 't');
                } else if (op == '&') {
                    stack.push(hasFalse ? 'f' : 't');
                } else if (op == '|') {
                    stack.push(hasTrue ? 't' : 'f');
                }
            }
        }
        return stack.pop() == 't';
    }
}

code.JavaScript:
function evaluateBooleanExpression(expression) {
    const stack = [];

    for (const char of expression) {
        if (char === ',') continue;

        if (char !== ')') {
            stack.push(char);
        } else {
            let hasTrue = false;
            let hasFalse = false;

            // Pop elements until we find the start of the current expression '('
            while (stack.length > 0 && stack[stack.length - 1] !== '(') {
                const val = stack.pop();
                // Check for either the string literal 't'/'f' or the boolean true/false
                if (val === 't' || val === true) hasTrue = true;
                if (val === 'f' || val === false) hasFalse = true;
            }

            stack.pop(); // Remove '('
            const operator = stack.pop(); // The operator character (!, &, |)

            let res;
            if (operator === '!') {
                res = !hasTrue; // Native Boolean NOT
            } else if (operator === '&') {
                res = !hasFalse; // Native AND logic (True if no false exists)
            } else if (operator === '|') {
                res = hasTrue; // Native OR logic (True if at least one true exists)
            }

            // Push the proper Boolean result back onto the stack
            stack.push(res);
        }
    }

    // Convert the final stack element to a primitive Boolean
    const final = stack[0];
    return final === 't' ? true : final === 'f' ? false : final;
}
